FILES["app/src/main/java/com/neroflix/tv/app/util/MidiLyricParser.java"] = 'package com.neroflix.tv.app.util;\n\nimport java.io.ByteArrayOutputStream;\nimport java.io.IOException;\nimport java.io.InputStream;\nimport java.util.ArrayList;\nimport java.util.Collections;\nimport java.util.Comparator;\nimport java.util.List;\n\n/**\n * Parses Standard MIDI Files (.mid / .kar) to extract embedded lyric events\n * (meta event type 0x05, with 0x01 Text events as fallback) and converts\n * their tick positions to absolute playback milliseconds using the file\'s\n * own tempo map. No audio synthesis here — MediaPlayer handles playback;\n * this only powers the synced lyric display.\n */\npublic class MidiLyricParser {\n\n    public static class LyricEvent {\n        public final long timeMs;\n        public final String text;\n        public LyricEvent(long timeMs, String text) {\n            this.timeMs = timeMs;\n            this.text = text;\n        }\n    }\n\n    /** A single syllable/word within a line, with its own trigger time —\n     *  this is what drives the karaoke guide\'s word-by-word highlight. */\n    public static class Syllable {\n        public final long timeMs;\n        public final String text;\n        public Syllable(long timeMs, String text) {\n            this.timeMs = timeMs;\n            this.text = text;\n        }\n    }\n\n    /** A full display line, built by joining consecutive syllable-level\n     *  LyricEvents until a "/" (new line) or "\\\\" (new paragraph) marker —\n     *  the standard .kar convention — which is consumed as a break, not\n     *  shown as literal text. The individual syllables (with their own\n     *  timings) are kept alongside the flattened `text` so the UI can\n     *  either show the plain line (fallback) or sweep-highlight it word\n     *  by word (karaoke guide) using the same data. */\n    public static class LyricLine {\n        public final long timeMs;\n        public final String text;\n        public final List<Syllable> syllables;\n        public LyricLine(long timeMs, String text, List<Syllable> syllables) {\n            this.timeMs = timeMs;\n            this.text = text;\n            this.syllables = syllables;\n        }\n    }\n\n    /** Groups raw syllable-level lyric events into full display lines,\n     *  keeping each syllable\'s own timing for karaoke highlighting.\n     *\n     *  A line breaks on the explicit "/" / "\\\\" karaoke markers where\n     *  present. But those markers are a .kar-file convention for the 0x05\n     *  Lyric meta event — files that only carry plain 0x01 Text events\n     *  (common in hymn/church MIDI packs) never use them at all, which\n     *  used to merge the *entire song* into one unbreakable line: the\n     *  sweep highlight would finish and then just sit there with nothing\n     *  to advance to. To handle that, a line also breaks automatically on\n     *  a natural pause between words (a timing gap suggesting a phrase\n     *  boundary) or once it\'s grown too long to read comfortably — so\n     *  files without real break markers still get sensible line-by-line\n     *  pacing instead of a single endless block. */\n    private static final long AUTO_BREAK_GAP_MS = 700;\n    private static final int AUTO_BREAK_MAX_CHARS = 48;\n\n    public static List<LyricLine> groupIntoLines(List<LyricEvent> events) {\n        List<LyricLine> lines = new ArrayList<>();\n        StringBuilder current = new StringBuilder();\n        List<Syllable> currentSyllables = new ArrayList<>();\n        long lineStart = -1;\n        long lastEventTime = -1;\n\n        for (LyricEvent ev : events) {\n            String raw = ev.text;\n            boolean isBreak = raw.startsWith("/") || raw.startsWith("\\\\");\n            boolean isCaretJoin = raw.startsWith("^");\n            String content = (isBreak || isCaretJoin) ? raw.substring(1) : raw;\n\n            boolean autoBreak = !isBreak && current.length() > 0 && (\n                (lastEventTime >= 0 && ev.timeMs - lastEventTime >= AUTO_BREAK_GAP_MS) ||\n                current.length() + content.length() > AUTO_BREAK_MAX_CHARS\n            );\n\n            if ((isBreak || autoBreak) && current.length() > 0) {\n                lines.add(new LyricLine(lineStart, current.toString().trim(), currentSyllables));\n                current.setLength(0);\n                currentSyllables = new ArrayList<>();\n                lineStart = -1;\n            }\n\n            if (lineStart < 0) lineStart = ev.timeMs;\n            if (!content.isEmpty()) {\n                currentSyllables.add(new Syllable(ev.timeMs, content));\n            }\n            current.append(content);\n            lastEventTime = ev.timeMs;\n        }\n\n        if (current.length() > 0) {\n            lines.add(new LyricLine(lineStart, current.toString().trim(), currentSyllables));\n        }\n\n        return lines;\n    }\n\n    private static final int DISPLAY_LINE_MAX_CHARS = 48;\n    private static final long DISPLAY_LINE_DEFAULT_MS = 3200;\n\n    /** Final safety pass: splits any line that\'s still too long to read\n     *  comfortably into shorter, advancing sub-lines — run on the\n     *  finished line list regardless of where it came from (MIDI or\n     *  online fallback).\n     *\n     *  This exists because some MIDI files store their lyrics as one\n     *  single Text meta-event holding an entire verse as one literal\n     *  string, rather than one event per word/syllable. Nothing earlier\n     *  in the pipeline can break a line like that: groupIntoLines only\n     *  ever breaks *between* separate events, and a single event has\n     *  nothing to break between. Such a file also isn\'t caught by the\n     *  "fall back to online lyrics" path, because that only triggers\n     *  when the MIDI produced *zero* lines — one giant line still counts\n     *  as "found lyrics," so the file\'s own (unsplittable) block was\n     *  used as-is. Running this pass last, after both sources have had\n     *  their chance, guarantees a long block gets split either way. */\n    public static List<LyricLine> splitLongLines(List<LyricLine> lines) {\n        List<LyricLine> out = new ArrayList<>();\n        for (int i = 0; i < lines.size(); i++) {\n            LyricLine line = lines.get(i);\n            if (line.text.length() <= DISPLAY_LINE_MAX_CHARS) {\n                out.add(line);\n                continue;\n            }\n            long nextStart = (i + 1 < lines.size()) ? lines.get(i + 1).timeMs : -1;\n            out.addAll(splitOneLongLine(line, nextStart));\n        }\n        return out;\n    }\n\n    private static List<LyricLine> splitOneLongLine(LyricLine line, long nextStart) {\n        List<LyricLine> result = new ArrayList<>();\n\n        // Prefer real per-word timing when there\'s more than one syllable\n        // to work with — this preserves exact sync for files that do\n        // have per-word events but just never got an explicit break.\n        List<Syllable> syllables = line.syllables;\n        if (syllables != null && syllables.size() > 1) {\n            StringBuilder chunk = new StringBuilder();\n            List<Syllable> chunkSylls = new ArrayList<>();\n            long chunkStart = -1;\n            for (Syllable s : syllables) {\n                if (chunk.length() > 0 && chunk.length() + s.text.length() > DISPLAY_LINE_MAX_CHARS) {\n                    result.add(new LyricLine(chunkStart, chunk.toString().trim(), new ArrayList<>(chunkSylls)));\n                    chunk.setLength(0);\n                    chunkSylls.clear();\n                    chunkStart = -1;\n                }\n                if (chunkStart < 0) chunkStart = s.timeMs;\n                chunk.append(s.text);\n                chunkSylls.add(s);\n            }\n            if (chunk.length() > 0) {\n                result.add(new LyricLine(chunkStart, chunk.toString().trim(), chunkSylls));\n            }\n            if (!result.isEmpty()) return result;\n        }\n\n        // Single event / no usable per-word timing: chunk the raw text by\n        // word boundaries and pace each chunk evenly, using the gap to\n        // the next known line where available, or a fixed reading pace\n        // otherwise — this is the case a single massive Text event hits.\n        String[] words = line.text.split("(?<=\\\\s)");\n        List<StringBuilder> chunks = new ArrayList<>();\n        StringBuilder chunk = new StringBuilder();\n        for (String w : words) {\n            if (chunk.length() > 0 && chunk.length() + w.length() > DISPLAY_LINE_MAX_CHARS) {\n                chunks.add(chunk);\n                chunk = new StringBuilder();\n            }\n            chunk.append(w);\n        }\n        if (chunk.length() > 0) chunks.add(chunk);\n        if (chunks.isEmpty()) {\n            result.add(line);\n            return result;\n        }\n\n        long totalWindow = (nextStart > line.timeMs)\n            ? (nextStart - line.timeMs)\n            : DISPLAY_LINE_DEFAULT_MS * chunks.size();\n        long perChunk = Math.max(800, totalWindow / chunks.size());\n        long cursor = line.timeMs;\n        for (StringBuilder c : chunks) {\n            String text = c.toString().trim();\n            String[] cw = c.toString().split("(?<=\\\\s)");\n            List<Syllable> est = new ArrayList<>();\n            long step = cw.length > 0 ? Math.max(50, (long) (perChunk * 0.85) / cw.length) : 0;\n            for (int j = 0; j < cw.length; j++) est.add(new Syllable(cursor + step * j, cw[j]));\n            result.add(new LyricLine(cursor, text, est));\n            cursor += perChunk;\n        }\n        return result;\n    }\n\n    private static class TempoChange {\n        final long tick;\n        final int microsPerQuarter;\n        TempoChange(long tick, int microsPerQuarter) {\n            this.tick = tick;\n            this.microsPerQuarter = microsPerQuarter;\n        }\n    }\n\n    public static List<LyricEvent> parse(InputStream in) throws IOException {\n        byte[] data = readAll(in);\n        int pos = 0;\n\n        if (!matchTag(data, pos, "MThd")) throw new IOException("Not a MIDI file");\n        pos += 4;\n        long headerLen = readUInt32(data, pos); pos += 4;\n        pos += 2; // format — unused\n        int numTracks = readUInt16(data, pos); pos += 2;\n        int division = readUInt16(data, pos); pos += 2;\n        pos += (int) (headerLen - 6);\n\n        boolean isSmpte = (division & 0x8000) != 0;\n        int ppq = 0;\n        double smpteMsPerTick = 0;\n        if (isSmpte) {\n            int smpteFps = -((byte) ((division >> 8) & 0xFF));\n            int ticksPerFrame = division & 0xFF;\n            if (smpteFps <= 0) smpteFps = 30; // safe fallback\n            if (ticksPerFrame <= 0) ticksPerFrame = 1;\n            smpteMsPerTick = 1000.0 / (smpteFps * ticksPerFrame);\n        } else {\n            ppq = division;\n        }\n\n        List<TempoChange> tempoChanges = new ArrayList<>();\n        tempoChanges.add(new TempoChange(0, 500000)); // default 120 BPM\n\n        List<Object[]> rawLyrics = new ArrayList<>(); // {tick(Long), text(String)}\n\n        for (int t = 0; t < numTracks && pos < data.length; t++) {\n            if (!matchTag(data, pos, "MTrk")) break;\n            pos += 4;\n            long trackLen = readUInt32(data, pos); pos += 4;\n            int trackEnd = (int) (pos + trackLen);\n\n            long tick = 0;\n            int runningStatus = 0;\n\n            while (pos < trackEnd) {\n                long[] vlq = readVarLen(data, pos);\n                long deltaTime = vlq[0];\n                pos = (int) vlq[1];\n                tick += deltaTime;\n\n                int statusByte = data[pos] & 0xFF;\n                if (statusByte < 0x80) {\n                    statusByte = runningStatus;\n                } else {\n                    pos++;\n                    runningStatus = statusByte;\n                }\n\n                if (statusByte == 0xFF) {\n                    int metaType = data[pos] & 0xFF; pos++;\n                    long[] lenVlq = readVarLen(data, pos);\n                    long len = lenVlq[0];\n                    pos = (int) lenVlq[1];\n\n                    if (metaType == 0x51 && len == 3) {\n                        int micros = ((data[pos] & 0xFF) << 16)\n                                   | ((data[pos + 1] & 0xFF) << 8)\n                                   | (data[pos + 2] & 0xFF);\n                        tempoChanges.add(new TempoChange(tick, micros));\n                    } else if (metaType == 0x05 || metaType == 0x01) {\n                        String text = new String(data, pos, (int) len, "ISO-8859-1");\n                        if (!text.isEmpty() && !text.startsWith("@")) {\n                            rawLyrics.add(new Object[]{tick, text});\n                        }\n                    }\n                    pos += (int) len;\n\n                    if (metaType == 0x2F) break; // end of track\n                } else if (statusByte == 0xF0 || statusByte == 0xF7) {\n                    long[] lenVlq = readVarLen(data, pos);\n                    long len = lenVlq[0];\n                    pos = (int) lenVlq[1];\n                    pos += (int) len;\n                } else {\n                    int type = statusByte & 0xF0;\n                    int dataBytes = (type == 0xC0 || type == 0xD0) ? 1 : 2;\n                    pos += dataBytes;\n                }\n            }\n            pos = trackEnd;\n        }\n\n        Collections.sort(tempoChanges, new Comparator<TempoChange>() {\n            @Override public int compare(TempoChange a, TempoChange b) {\n                return Long.compare(a.tick, b.tick);\n            }\n        });\n\n        List<LyricEvent> result = new ArrayList<>();\n        for (Object[] entry : rawLyrics) {\n            long tick = (Long) entry[0];\n            String text = (String) entry[1];\n            long tickMs = isSmpte\n                ? Math.round(tick * smpteMsPerTick)\n                : ticksToMs(tick, tempoChanges, ppq);\n            result.add(new LyricEvent(tickMs, text));\n        }\n\n        Collections.sort(result, new Comparator<LyricEvent>() {\n            @Override public int compare(LyricEvent a, LyricEvent b) {\n                return Long.compare(a.timeMs, b.timeMs);\n            }\n        });\n\n        return result;\n    }\n\n    private static long ticksToMs(long targetTick, List<TempoChange> tempoChanges, int ppq) {\n        double ms = 0;\n        long lastTick = 0;\n        int lastMicros = tempoChanges.get(0).microsPerQuarter;\n\n        for (TempoChange tc : tempoChanges) {\n            if (tc.tick >= targetTick) break;\n            long segmentTicks = tc.tick - lastTick;\n            ms += (segmentTicks / (double) ppq) * (lastMicros / 1000.0);\n            lastTick = tc.tick;\n            lastMicros = tc.microsPerQuarter;\n        }\n        long remainingTicks = targetTick - lastTick;\n        ms += (remainingTicks / (double) ppq) * (lastMicros / 1000.0);\n        return Math.round(ms);\n    }\n\n    private static boolean matchTag(byte[] data, int pos, String tag) {\n        if (pos + 4 > data.length) return false;\n        for (int i = 0; i < 4; i++) {\n            if (data[pos + i] != (byte) tag.charAt(i)) return false;\n        }\n        return true;\n    }\n\n    private static long readUInt32(byte[] data, int pos) {\n        return ((data[pos] & 0xFFL) << 24) | ((data[pos + 1] & 0xFFL) << 16)\n             | ((data[pos + 2] & 0xFFL) << 8) | (data[pos + 3] & 0xFFL);\n    }\n\n    private static int readUInt16(byte[] data, int pos) {\n        return ((data[pos] & 0xFF) << 8) | (data[pos + 1] & 0xFF);\n    }\n\n    /** Returns {value, newPos} */\n    private static long[] readVarLen(byte[] data, int pos) {\n        long value = 0;\n        int b;\n        do {\n            b = data[pos] & 0xFF;\n            pos++;\n            value = (value << 7) | (b & 0x7F);\n        } while ((b & 0x80) != 0);\n        return new long[]{value, pos};\n    }\n\n    private static byte[] readAll(InputStream in) throws IOException {\n        ByteArrayOutputStream buffer = new ByteArrayOutputStream();\n        byte[] chunk = new byte[8192];\n        int bytesRead;\n        while ((bytesRead = in.read(chunk)) != -1) {\n            buffer.write(chunk, 0, bytesRead);\n        }\n        return buffer.toByteArray();\n    }\n}\n'
FILES["app/src/main/java/com/neroflix/tv/app/activities/KaraokePlayerActivity.java"] = 'package com.neroflix.tv.app.activities;\n\nimport android.media.MediaPlayer;\nimport android.net.Uri;\nimport android.os.Bundle;\nimport android.os.Handler;\nimport android.os.Looper;\nimport android.text.TextUtils;\nimport android.view.KeyEvent;\nimport android.widget.ProgressBar;\nimport android.widget.TextView;\n\nimport androidx.appcompat.app.AppCompatActivity;\nimport androidx.media3.common.MediaItem;\nimport androidx.media3.common.Player;\nimport androidx.media3.exoplayer.ExoPlayer;\nimport androidx.media3.ui.PlayerView;\n\nimport com.neroflix.tv.app.R;\nimport com.neroflix.tv.app.util.MidiLyricParser;\n\nimport java.io.File;\nimport java.io.FileInputStream;\nimport java.io.FileOutputStream;\nimport java.io.InputStream;\nimport java.util.ArrayList;\nimport java.util.List;\nimport java.util.concurrent.ExecutorService;\nimport java.util.concurrent.Executors;\n\nimport okhttp3.OkHttpClient;\nimport okhttp3.Request;\nimport okhttp3.Response;\n\npublic class KaraokePlayerActivity extends AppCompatActivity {\n\n    private ProgressBar loadingBar;\n    private TextView titleText;\n    private TextView playPauseBtn;\n    private TextView backBtn;\n    private TextView lyricRowA, lyricRowB;\n    private PlayerView bgVideoView;\n\n    private String songTitle, songArtist, songMidiUrl;\n\n    private MediaPlayer mediaPlayer;\n    private ExoPlayer bgPlayer;\n    private List<MidiLyricParser.LyricLine> lyricLines;\n    private int currentLyricIndex = -1;\n    private boolean isPlaying = false;\n    private boolean rowAActive = true;\n    private boolean lyricRowsInitialized = false;\n    // The row currently showing the "singing now" line, and the line data\n    // behind it — needed so the sweep highlight can be refreshed every\n    // tick without waiting for the active line to change.\n    private TextView activeRow;\n    private MidiLyricParser.LyricLine activeLine;\n\n    // Background videos shipped inside the APK under assets/bgv — every\n    // video found there is loaded into a shuffled, endlessly-looping,\n    // muted playlist that plays behind the lyrics.\n    private static final String BG_VIDEO_ASSET_DIR = "bgv";\n    private static final String[] BG_VIDEO_EXTENSIONS =\n        {".mp4", ".mkv", ".webm", ".avi", ".mov", ".3gp", ".m4v"};\n\n    // Fixed sync offset in ms, added to playback position before matching a\n    // lyric line. Positive = lines trigger earlier (compensates for lyrics\n    // that appear "late"/behind the vocals). Negative = lines trigger later\n    // (compensates for lyrics that appear "early"/ahead of the vocals).\n    // Persisted so it carries across songs/sessions once the user tunes it.\n    private static final String PREFS_NAME = "karaoke_prefs";\n    private static final String PREF_OFFSET_MS = "lyric_offset_ms";\n    private static final long OFFSET_STEP_MS = 100;\n    private long lyricOffsetMs = 0;\n\n    private final ExecutorService executor = Executors.newSingleThreadExecutor();\n    private final Handler mainHandler = new Handler(Looper.getMainLooper());\n    private final OkHttpClient http = new OkHttpClient();\n\n    private final Runnable lyricUpdateRunnable = new Runnable() {\n        @Override public void run() {\n            updateLyricDisplay();\n            mainHandler.postDelayed(this, 80);\n        }\n    };\n\n    @Override\n    protected void onCreate(Bundle savedInstanceState) {\n        super.onCreate(savedInstanceState);\n        setContentView(R.layout.activity_karaoke_player);\n\n        loadingBar   = findViewById(R.id.karplay_loading);\n        titleText    = findViewById(R.id.karplay_title);\n        playPauseBtn = findViewById(R.id.karplay_play_pause_btn);\n        backBtn      = findViewById(R.id.karplay_back_btn);\n        lyricRowA    = findViewById(R.id.karplay_lyric_row_a);\n        lyricRowB    = findViewById(R.id.karplay_lyric_row_b);\n        bgVideoView  = findViewById(R.id.karplay_bg_video);\n\n        songTitle   = getIntent().getStringExtra("song_title");\n        songArtist  = getIntent().getStringExtra("song_artist");\n        songMidiUrl = getIntent().getStringExtra("song_midi_url");\n\n        lyricOffsetMs = getSharedPreferences(PREFS_NAME, MODE_PRIVATE)\n            .getLong(PREF_OFFSET_MS, 0);\n\n        loadBackgroundVideos();\n\n        titleText.setText(TextUtils.isEmpty(songArtist)\n            ? songTitle : songTitle + "  •  " + songArtist);\n\n        if (backBtn != null) backBtn.setOnClickListener(v -> finish());\n        if (playPauseBtn != null) playPauseBtn.setOnClickListener(v -> togglePlayPause());\n\n        loadAndPlay();\n    }\n\n    private void loadAndPlay() {\n        if (songMidiUrl == null || songMidiUrl.isEmpty()) {\n            lyricRowA.setText("Invalid song.");\n            return;\n        }\n\n        loadingBar.setVisibility(android.view.View.VISIBLE);\n        lyricRowA.setText("");\n        lyricRowB.setText("");\n        rowAActive = true;\n        lyricRowsInitialized = false;\n        activeRow = null;\n        activeLine = null;\n\n        executor.execute(() -> {\n            try {\n                File cacheFile = new File(getCacheDir(), "karaoke_" + Math.abs(songMidiUrl.hashCode()) + ".mid");\n                if (!cacheFile.exists()) {\n                    Request req = new Request.Builder().url(songMidiUrl).build();\n                    Response resp = http.newCall(req).execute();\n                    if (!resp.isSuccessful() || resp.body() == null) throw new Exception("HTTP " + resp.code());\n                    FileOutputStream fos = new FileOutputStream(cacheFile);\n                    try {\n                        fos.write(resp.body().bytes());\n                    } finally {\n                        fos.close();\n                    }\n                }\n\n                List<MidiLyricParser.LyricEvent> parsedEvents;\n                InputStream in = new FileInputStream(cacheFile);\n                try {\n                    parsedEvents = MidiLyricParser.parse(in);\n                } finally {\n                    in.close();\n                }\n                List<MidiLyricParser.LyricLine> parsedLines =\n                    MidiLyricParser.groupIntoLines(parsedEvents);\n\n                // Fallback: if the MIDI itself has no embedded lyrics, try\n                // fetching synced lyrics online via lrclib.net using the\n                // song\'s title/artist.\n                if (parsedLines.isEmpty()) {\n                    List<MidiLyricParser.LyricLine> onlineLines =\n                        com.neroflix.tv.app.util.LrcLyricFetcher.fetch(http, songTitle, songArtist);\n                    if (onlineLines != null && !onlineLines.isEmpty()) {\n                        parsedLines = onlineLines;\n                    }\n                }\n                // Defensive: the line-index walk that drives playback sync\n                // assumes non-decreasing timestamps. Sorting here (on top\n                // of the sort each source already does) guarantees that\n                // regardless of where the lines came from, so a single\n                // out-of-order entry can never freeze the display on an\n                // early line for the rest of the song.\n                List<MidiLyricParser.LyricLine> sortedLines = new ArrayList<>(parsedLines);\n                java.util.Collections.sort(sortedLines, (a, b) -> Long.compare(a.timeMs, b.timeMs));\n                // Splits any line too long to read comfortably into shorter\n                // advancing sub-lines — needed for MIDI files that store an\n                // entire verse as one single Text event, which nothing\n                // earlier in the pipeline (from either source) can break up.\n                final List<MidiLyricParser.LyricLine> finalLines =\n                    MidiLyricParser.splitLongLines(sortedLines);\n\n                mainHandler.post(() -> {\n                    lyricLines = finalLines;\n                    currentLyricIndex = -1;\n                    if (lyricLines.isEmpty()) {\n                        lyricRowA.setText("🎵 No lyrics available");\n                        lyricRowB.setText("");\n                    }\n                    startPlayback(cacheFile);\n                });\n            } catch (Exception e) {\n                android.util.Log.e("KaraokePlayer", "loadAndPlay failed", e);\n                final String errMsg = e.getClass().getSimpleName() + ": " + e.getMessage();\n                mainHandler.post(() -> {\n                    loadingBar.setVisibility(android.view.View.GONE);\n                    lyricRowA.setText("Failed to load song.");\n                    lyricRowB.setText(errMsg);\n                });\n            }\n        });\n    }\n\n    /** Lists every video in assets/bgv, shuffles them into a looping\n     *  muted playlist, and starts it behind the lyrics. If the folder\n     *  is missing or empty, the screen just falls back to the plain\n     *  dark background — this never blocks song playback.\n     *\n     *  The list is shuffled here (not just via ExoPlayer\'s shuffle mode)\n     *  because enabling shuffle mode only randomizes which item plays\n     *  *next* — the item at index 0 still plays first every time, and\n     *  since AssetManager.list() returns names in the same deterministic\n     *  order on every call, every song was opening on the same video. */\n    private void loadBackgroundVideos() {\n        executor.execute(() -> {\n            List<String> videoNames = new ArrayList<>();\n            try {\n                String[] names = getAssets().list(BG_VIDEO_ASSET_DIR);\n                if (names != null) {\n                    for (String name : names) {\n                        String lower = name.toLowerCase(java.util.Locale.US);\n                        for (String ext : BG_VIDEO_EXTENSIONS) {\n                            if (lower.endsWith(ext)) {\n                                videoNames.add(name);\n                                break;\n                            }\n                        }\n                    }\n                }\n            } catch (Exception e) {\n                android.util.Log.w("KaraokePlayer", "No background videos found in assets/" + BG_VIDEO_ASSET_DIR, e);\n            }\n\n            if (videoNames.isEmpty()) return;\n\n            java.util.Collections.shuffle(videoNames, new java.util.Random());\n\n            final List<Uri> uris = new ArrayList<>();\n            for (String name : videoNames) {\n                uris.add(Uri.parse("asset:///" + BG_VIDEO_ASSET_DIR + "/" + name));\n            }\n            mainHandler.post(() -> initBgPlayer(uris));\n        });\n    }\n\n    private void initBgPlayer(List<Uri> uris) {\n        if (bgVideoView == null || uris.isEmpty()) return;\n        try {\n            bgPlayer = new ExoPlayer.Builder(this).build();\n            bgVideoView.setPlayer(bgPlayer);\n\n            List<MediaItem> items = new ArrayList<>();\n            for (Uri uri : uris) items.add(MediaItem.fromUri(uri));\n\n            bgPlayer.setMediaItems(items);\n            bgPlayer.setShuffleModeEnabled(true);\n            bgPlayer.setRepeatMode(Player.REPEAT_MODE_ALL);\n            bgPlayer.setVolume(0f);\n            bgPlayer.prepare();\n            // The background loop is silent and purely decorative, so it\n            // should start rolling as soon as it\'s ready rather than\n            // waiting on `isPlaying` — that flag is still false at this\n            // point because the MIDI download/parse (on another thread)\n            // usually hasn\'t finished yet, and nothing ever flipped this\n            // player\'s playWhenReady on afterward. That left it sitting on\n            // its first decoded frame — a static image, not a video.\n            bgPlayer.setPlayWhenReady(true);\n        } catch (Exception e) {\n            android.util.Log.e("KaraokePlayer", "initBgPlayer failed", e);\n        }\n    }\n\n    private void startPlayback(File file) {\n        try {\n            mediaPlayer = new MediaPlayer();\n            mediaPlayer.setDataSource(file.getAbsolutePath());\n            mediaPlayer.setOnPreparedListener(mp -> {\n                loadingBar.setVisibility(android.view.View.GONE);\n                mp.start();\n                isPlaying = true;\n                updatePlayPauseIcon();\n                mainHandler.post(lyricUpdateRunnable);\n            });\n            mediaPlayer.setOnCompletionListener(mp -> {\n                isPlaying = false;\n                updatePlayPauseIcon();\n                mainHandler.removeCallbacks(lyricUpdateRunnable);\n                finish();\n            });\n            mediaPlayer.setOnErrorListener((mp, what, extra) -> {\n                android.util.Log.e("KaraokePlayer", "MediaPlayer error: " + what + "/" + extra);\n                loadingBar.setVisibility(android.view.View.GONE);\n                lyricRowA.setText("Playback error.");\n                return true;\n            });\n            mediaPlayer.prepareAsync();\n        } catch (Exception e) {\n            loadingBar.setVisibility(android.view.View.GONE);\n            lyricRowA.setText("Failed to play song.");\n            android.util.Log.e("KaraokePlayer", "startPlayback failed", e);\n        }\n    }\n\n    private void togglePlayPause() {\n        if (mediaPlayer == null) return;\n        try {\n            if (isPlaying) {\n                mediaPlayer.pause();\n                isPlaying = false;\n                mainHandler.removeCallbacks(lyricUpdateRunnable);\n            } else {\n                mediaPlayer.start();\n                isPlaying = true;\n                mainHandler.post(lyricUpdateRunnable);\n            }\n            if (bgPlayer != null) bgPlayer.setPlayWhenReady(isPlaying);\n            updatePlayPauseIcon();\n        } catch (Exception ignored) {}\n    }\n\n    private void updatePlayPauseIcon() {\n        if (playPauseBtn != null) playPauseBtn.setText(isPlaying ? "⏸" : "▶");\n    }\n\n    private void updateLyricDisplay() {\n        if (mediaPlayer == null || lyricLines == null || lyricLines.isEmpty()) return;\n        long pos;\n        try {\n            pos = mediaPlayer.getCurrentPosition();\n        } catch (Exception e) {\n            return;\n        }\n        long adjPos = pos + lyricOffsetMs;\n\n        // Full scan (not break-on-first-miss) so a single out-of-order\n        // timestamp can\'t strand the index on an early line for the rest\n        // of playback — it just finds the last line that has started.\n        int idx = -1;\n        for (int i = 0; i < lyricLines.size(); i++) {\n            if (lyricLines.get(i).timeMs <= adjPos) idx = i;\n        }\n\n        if (idx != currentLyricIndex) {\n            currentLyricIndex = idx;\n\n            MidiLyricParser.LyricLine currLine = idx >= 0 ? lyricLines.get(idx) : null;\n            String nextText = idx + 1 < lyricLines.size() ? lyricLines.get(idx + 1).text : "";\n\n            if (!lyricRowsInitialized) {\n                setRowWaiting(lyricRowB, nextText);\n                activeRow = lyricRowA;\n                rowAActive = true;\n                lyricRowsInitialized = true;\n            } else if (rowAActive) {\n                setRowWaiting(lyricRowA, nextText);\n                activeRow = lyricRowB;\n                rowAActive = false;\n            } else {\n                setRowWaiting(lyricRowB, nextText);\n                activeRow = lyricRowA;\n                rowAActive = true;\n            }\n            activeLine = currLine;\n            setRowActiveStyle(activeRow);\n        }\n\n        // Refresh the karaoke-guide sweep on the active line every tick,\n        // independent of whether the line itself just changed, so the\n        // highlight progresses smoothly word-by-word as the song plays.\n        updateActiveRowHighlight(adjPos);\n    }\n\n    /** Repaints the active row\'s text with the karaoke-guide sweep: the\n     *  words already sung (their syllable timestamp has passed) in the\n     *  bright highlight color, and the words still to come in white. This\n     *  is what makes word-by-word/syllable highlighting actually visible —\n     *  previously the active line was just set to one flat color. */\n    private void updateActiveRowHighlight(long adjPos) {\n        if (activeRow == null) return;\n        if (activeLine == null) {\n            activeRow.setText("");\n            return;\n        }\n        List<MidiLyricParser.Syllable> syllables = activeLine.syllables;\n        if (syllables == null || syllables.isEmpty()) {\n            // No syllable-level timing available — show the plain line\n            // (still correctly synced, just without the word sweep).\n            activeRow.setText(activeLine.text);\n            return;\n        }\n\n        StringBuilder full = new StringBuilder();\n        int sungChars = 0;\n        for (MidiLyricParser.Syllable s : syllables) {\n            full.append(s.text);\n            if (s.timeMs <= adjPos) sungChars = full.length();\n        }\n\n        String text = full.toString();\n        android.text.SpannableString sp = new android.text.SpannableString(text);\n        if (sungChars > 0) {\n            sp.setSpan(new android.text.style.ForegroundColorSpan(SUNG_COLOR),\n                0, Math.min(sungChars, text.length()),\n                android.text.Spannable.SPAN_EXCLUSIVE_EXCLUSIVE);\n        }\n        if (sungChars < text.length()) {\n            sp.setSpan(new android.text.style.ForegroundColorSpan(UPCOMING_COLOR),\n                sungChars, text.length(),\n                android.text.Spannable.SPAN_EXCLUSIVE_EXCLUSIVE);\n        }\n        activeRow.setText(sp);\n    }\n\n    private static final int SUNG_COLOR = android.graphics.Color.parseColor("#4DD9FF");\n    private static final int UPCOMING_COLOR = android.graphics.Color.parseColor("#FFFFFF");\n\n    private void setRowActiveStyle(TextView row) {\n        row.setTextSize(34);\n        row.setAlpha(1f);\n    }\n\n    private void setRowWaiting(TextView row, String text) {\n        row.setText(text);\n        row.setTextColor(android.graphics.Color.parseColor("#888888"));\n        row.setTextSize(24);\n        row.setAlpha(0.85f);\n    }\n\n    @Override\n    public boolean onKeyDown(int keyCode, KeyEvent event) {\n        switch (keyCode) {\n            case KeyEvent.KEYCODE_DPAD_CENTER:\n            case KeyEvent.KEYCODE_ENTER:\n            case KeyEvent.KEYCODE_MEDIA_PLAY_PAUSE:\n                togglePlayPause(); return true;\n            case KeyEvent.KEYCODE_DPAD_LEFT:\n                adjustLyricOffset(-OFFSET_STEP_MS); return true;\n            case KeyEvent.KEYCODE_DPAD_RIGHT:\n                adjustLyricOffset(OFFSET_STEP_MS); return true;\n            case KeyEvent.KEYCODE_BACK:\n            case KeyEvent.KEYCODE_ESCAPE:\n                finish(); return true;\n        }\n        return super.onKeyDown(keyCode, event);\n    }\n\n    /** Nudges the lyric sync offset and persists it for future songs.\n     *  Positive delta makes lines trigger earlier (for lyrics that lag\n     *  behind the vocals); negative delta makes them trigger later. */\n    private void adjustLyricOffset(long deltaMs) {\n        lyricOffsetMs += deltaMs;\n        getSharedPreferences(PREFS_NAME, MODE_PRIVATE)\n            .edit().putLong(PREF_OFFSET_MS, lyricOffsetMs).apply();\n        android.widget.Toast.makeText(this,\n            "Lyric sync: " + (lyricOffsetMs >= 0 ? "+" : "") + lyricOffsetMs + "ms",\n            android.widget.Toast.LENGTH_SHORT).show();\n    }\n\n    @Override\n    protected void onDestroy() {\n        super.onDestroy();\n        mainHandler.removeCallbacks(lyricUpdateRunnable);\n        if (mediaPlayer != null) {\n            try { mediaPlayer.stop(); } catch (Exception ignored) {}\n            try { mediaPlayer.release(); } catch (Exception ignored) {}\n            mediaPlayer = null;\n        }\n        if (bgPlayer != null) {\n            try { bgVideoView.setPlayer(null); } catch (Exception ignored) {}\n            try { bgPlayer.release(); } catch (Exception ignored) {}\n            bgPlayer = null;\n        }\n        executor.shutdownNow();\n    }\n}\n'

def main():
    repo_root = os.getcwd()
    changed = []
    missing = []
    for relpath, content in FILES.items():
        full_path = os.path.join(repo_root, relpath)
        if not os.path.exists(full_path):
            missing.append(relpath)
            continue
        with open(full_path, "w", encoding="utf-8", newline="\n") as f:
            f.write(content)
        changed.append(relpath)

    print("Updated files:")
    for r in changed:
        print("  -", r)

    if missing:
        print()
        print("WARNING: these expected files were not found under the current directory")
        print("(run this script from the repo root):")
        for r in missing:
            print("  -", r)
        sys.exit(1)

    print()
    print("Now commit and push, e.g.:")
    print("  git add -A")
    print('  git commit -m "Split single-event MIDI lyric blocks that groupIntoLines could not break"')
    print("  git push")

if __name__ == "__main__":
    main()
